mapper.select:
SELECT * FROM company
AND (name LIKE CONCAT('%', #{keyword}, '%') OR unified_social_credit_code LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY create_time DESC LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE company
unified_social_credit_code = #{unifiedSocialCreditCode}, name = #{name}, region_id = #{regionId}, legal_person = #{legalPerson}, contact_phone = #{contactPhone}, status = #{status}, update_time = #{updateTime},
WHERE id = #{id}
